import{_ as p,o as t,c as a,a2 as r}from"./chunks/framework.BbQrW5_t.js";const s="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",o="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",B="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",g="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",n="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",d="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",E="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",F="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",e="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==",c=JSON.parse('{"title":"特殊平行四边形 — 广州中考典型试题与解析","description":"","frontmatter":{},"headers":[],"relativePath":"study/junior-math/exam/special-quadrilaterals.md","filePath":"study/junior-math/exam/special-quadrilaterals.md","lastUpdated":1783652711000}'),C={name:"study/junior-math/exam/special-quadrilaterals.md"};function D(h,A,l,m,x,u){return t(),a("div",null,[...A[0]||(A[0]=[r('<h1 id="特殊平行四边形-—-广州中考典型试题与解析" tabindex="-1">特殊平行四边形 — 广州中考典型试题与解析 <a class="header-anchor" href="#特殊平行四边形-—-广州中考典型试题与解析" aria-label="Permalink to &quot;特殊平行四边形 — 广州中考典型试题与解析&quot;">​</a></h1><blockquote><p>特殊平行四边形（矩形、菱形、正方形）是广州中考几何大题的常客，分值 8-10 分。</p><p>难度标注：⭐ 基础 | ⭐⭐ 中等 | ⭐⭐⭐ 较难 | ⭐⭐⭐⭐ 压轴</p></blockquote><hr><h3 id="案例-1-矩形性质与判定-⭐" tabindex="-1">案例 1：矩形性质与判定 ⭐ <a class="header-anchor" href="#案例-1-矩形性质与判定-⭐" aria-label="Permalink to &quot;案例 1：矩形性质与判定 ⭐&quot;">​</a></h3><p><img src="'+s+'" alt="案例1示意图"></p><p><strong>【题目】</strong> 矩形 ABCD 中，AB = 6，BC = 8，对角线 AC 与 BD 交于点 O。求：(1) 对角线 AC 的长；(2) 点 O 到 AB 的距离。</p><p><strong>【解析】</strong></p><p>(1) 矩形中 ∠ABC = 90°，由勾股定理：</p><p>AC² = AB² + BC² = 36 + 64 = 100</p><p>AC = 10</p><p>(2) 矩形对角线互相平分且相等，O 为 AC 中点。</p><p>O 到 AB 的距离 = O 的纵坐标（以 A 为原点，AB 为 x 轴方向）</p><p>O 到 AB 的距离 = BC/2 = 4</p><p><strong>答：</strong>(1) AC = 10；(2) O 到 AB 的距离为 4</p><p><strong>【方法提炼】</strong> 矩形的核心性质：四个角为直角 + 对角线相等且互相平分。求距离时注意利用对称性简化计算。</p><hr><h3 id="案例-2-菱形性质与判定-⭐" tabindex="-1">案例 2：菱形性质与判定 ⭐ <a class="header-anchor" href="#案例-2-菱形性质与判定-⭐" aria-label="Permalink to &quot;案例 2：菱形性质与判定 ⭐&quot;">​</a></h3><p><img src="'+o+'" alt="案例2示意图"></p><p><strong>【题目】</strong> 菱形 ABCD 的对角线 AC = 6，BD = 8，交于点 O。求：(1) 菱形的面积；(2) 菱形的边长。</p><p><strong>【解析】</strong></p><p>(1) 菱形面积 = 对角线乘积的一半：</p><p>S = ½ × AC × BD = ½ × 6 × 8 = 24</p><p>(2) 菱形对角线互相垂直平分，在 Rt▵AOB 中：</p><p>OA = 3，OB = 4</p><p>AB² = OA² + OB² = 9 + 16 = 25</p><p>AB = 5</p><p><strong>答：</strong>(1) 面积为 24；(2) 边长为 5</p><p><strong>【方法提炼】</strong> 菱形两大核心性质：四边相等 + 对角线互相垂直平分。面积公式 S = ½d&amp;sub1;d&amp;sub2; 比底×高更常用。</p><hr><h3 id="案例-3-正方形性质-⭐⭐" tabindex="-1">案例 3：正方形性质 ⭐⭐ <a class="header-anchor" href="#案例-3-正方形性质-⭐⭐" aria-label="Permalink to &quot;案例 3：正方形性质 ⭐⭐&quot;">​</a></h3><p><img src="'+B+'" alt="案例3示意图"></p><p><strong>【题目】</strong> 正方形 ABCD 的边长为 6，E 在 BC 上，F 在 CD 上，且 BE = CF = 2。求证：AE ⊥ BF。</p><p><strong>【解析】</strong></p><p>∵ ABCD 为正方形，∴ AB = BC，∠ABE = ∠BCF = 90°</p><p>又 BE = CF = 2</p><p>∴ ▵ABE ≅ ▵BCF (SAS)</p><p>∴ ∠BAE = ∠CBF</p><p>设 AE 与 BF 交于 G，</p><p>在 ▵ABG 中，∠ABG + ∠BAG = ∠ABG + ∠CBF = ∠ABE = 90°</p><p>∴ ∠AGB = 180° − 90° = 90°</p><p>即 AE ⊥ BF</p><p><strong>答：</strong> AE ⊥ BF</p><p><strong>【方法提炼】</strong> 正方形中证明垂直的经典方法：构造全等三角形转移角，利用互余关系得直角。BE = CF 是常见的&quot;截取等长&quot;条件。</p><hr><h3 id="案例-4-平行四边形中的折叠问题-⭐⭐" tabindex="-1">案例 4：平行四边形中的折叠问题 ⭐⭐ <a class="header-anchor" href="#案例-4-平行四边形中的折叠问题-⭐⭐" aria-label="Permalink to &quot;案例 4：平行四边形中的折叠问题 ⭐⭐&quot;">​</a></h3><p><img src="'+g+'" alt="案例4示意图"></p><p><strong>【题目】</strong> 矩形 ABCD 中，AB = 3，BC = 6，沿 EF 折叠使 A 落在 BC 上的 A&#39; 处，且 BA&#39; = 4。求折痕 EF 的长。</p><p><strong>【解析】</strong></p><p>折叠前后对应边相等：A&#39;E = AE，A&#39;F = AF</p><p>在 Rt▵ABA&#39; 中：</p><p>BA&#39; = 4，AB = 3</p><p>AA&#39;² = AB² + BA&#39;² = 9 + 16 = 25，AA&#39; = 5</p><p>设 AE = x，则 A&#39;E = x，BE = 6 − x</p><p>在 Rt▵BA&#39;E 中：BE² + BA&#39;² = A&#39;E²</p><p>(6 − x)² + 16 = x²</p><p>36 − 12x + x² + 16 = x²</p><p>52 = 12x，x = 13/3</p><p>∴ AE = 13/3</p><p>同理设 AF = y，则 A&#39;F = y</p><p>在 Rt▵A&#39;CF 中：A&#39;F² = CF² + A&#39;C²</p><p>y² = (6 − y)² + 1² = 36 − 12y + y² + 1</p><p>0 = 37 − 12y，y = 37/12</p><p>在 Rt▵AEF 中：</p><p>EF² = AE² + AF² = (13/3)² + (37/12)² = 169/9 + 1369/144</p><p>= 2704/144 + 1369/144 = 4073/144</p><p>EF = √(4073)/12</p><p>化简 4073 = 4073（素数），EF = √4073 / 12</p><p><strong>答：</strong> EF = √4073 / 12</p><p><strong>【方法提炼】</strong> 折叠问题的核心：折叠前后对应边相等、对应角相等。在矩形折叠中，落点在边上时，勾股定理列方程是基本方法。</p><hr><h3 id="案例-5-矩形中的动点问题-⭐⭐" tabindex="-1">案例 5：矩形中的动点问题 ⭐⭐ <a class="header-anchor" href="#案例-5-矩形中的动点问题-⭐⭐" aria-label="Permalink to &quot;案例 5：矩形中的动点问题 ⭐⭐&quot;">​</a></h3><p><img src="'+n+'" alt="案例5示意图"></p><p><strong>【题目】</strong> 矩形 ABCD 中，AB = 8，BC = 6，点 P 从 A 沿 AD 向 D 移动，AP = t (0 ≤ t ≤ 6)。当 ▵BPC 为等腰三角形时，求 t 的值。</p><p><strong>【解析】</strong></p><p>BC = 6，BP = √(AB² + AP²) = √(64 + t²)，CP = √(CD² + DP²) = √(64 + (6−t)²)</p><p>分三种情况：</p><p><strong>情况一：BP = BC = 6</strong></p><p>64 + t² = 36，t² = −28，无解</p><p><strong>情况二：CP = BC = 6</strong></p><p>64 + (6−t)² = 36，(6−t)² = −28，无解</p><p><strong>情况三：BP = CP</strong></p><p>√(64 + t²) = √(64 + (6−t)²)</p><p>t² = (6−t)² = 36 − 12t + t²</p><p>12t = 36，t = 3</p><p>验证：t = 3 时，BP = CP = √73 ≠ 6 = BC，▵BPC 为等腰三角形 ✓</p><p><strong>答：</strong> t = 3</p><p><strong>【方法提炼】</strong> 矩形中动点构成等腰三角形，需分三种情况讨论。本题只有 BP = CP 一种情况有解，因为 P 在 AD 上时 BP、CP 总大于 BC。</p><hr><h3 id="案例-6-菱形面积与对角线-⭐⭐⭐" tabindex="-1">案例 6：菱形面积与对角线 ⭐⭐⭐ <a class="header-anchor" href="#案例-6-菱形面积与对角线-⭐⭐⭐" aria-label="Permalink to &quot;案例 6：菱形面积与对角线 ⭐⭐⭐&quot;">​</a></h3><p><img src="'+d+'" alt="案例6示意图"></p><p><strong>【题目】</strong> 菱形 ABCD 的对角线 AC = 12，BD = 16，点 E 在 AB 上，EF ⊥ BD 于 F。求 EF 的长。</p><p><strong>【解析】</strong></p><p>菱形对角线互相垂直平分：</p><p>OA = 6，OB = 8，AB = √(36 + 64) = 10</p><p>S▵ABD = ½ × BD × OA = ½ × 16 × 6 = 48</p><p>又 S▵ABD = ½ × AB × EF（以 AB 为底，EF 为 A 到 BD 的距离转换）</p><p>但更直接：S▵ABD = ½ × BD × EF</p><p>48 = ½ × 16 × EF</p><p>EF = 6</p><p><strong>答：</strong> EF = 6</p><p><strong>【方法提炼】</strong> 菱形中求点到对角线的距离，利用面积等积法最快捷：½d&amp;sub1; × d&amp;sub2; = ½d&amp;sub1; × h，其中 h 即为所求距离。</p><hr><h3 id="案例-7-四边形综合证明-⭐⭐⭐" tabindex="-1">案例 7：四边形综合证明 ⭐⭐⭐ <a class="header-anchor" href="#案例-7-四边形综合证明-⭐⭐⭐" aria-label="Permalink to &quot;案例 7：四边形综合证明 ⭐⭐⭐&quot;">​</a></h3><p><img src="'+E+'" alt="案例7示意图"></p><p><strong>【题目】</strong> 平行四边形 ABCD 中，E、F 分别在 AB、CD 上，且 AE = CF。求证：DEBF 是平行四边形。</p><p><strong>【解析】</strong></p><p>∵ ABCD 为平行四边形</p><p>∴ AB // CD，AB = CD</p><p>又 AE = CF</p><p>∴ AB − AE = CD − CF，即 EB = DF</p><p>又 EB // DF（EB ⊆ AB，DF ⊆ CD，AB // CD）</p><p>一组对边平行且相等</p><p>∴ DEBF 为平行四边形</p><p><strong>答：</strong> DEBF 是平行四边形</p><p><strong>【方法提炼】</strong> 在平行四边形中截取等长线段，常用&quot;一组对边平行且相等&quot;判定平行四边形，这是最简洁的判定方法。</p><hr><h3 id="案例-8-特殊四边形与全等三角形-⭐⭐⭐" tabindex="-1">案例 8：特殊四边形与全等三角形 ⭐⭐⭐ <a class="header-anchor" href="#案例-8-特殊四边形与全等三角形-⭐⭐⭐" aria-label="Permalink to &quot;案例 8：特殊四边形与全等三角形 ⭐⭐⭐&quot;">​</a></h3><p><img src="'+F+'" alt="案例8示意图"></p><p><strong>【题目】</strong> 正方形 ABCD 的边长为 1，E 在 BC 上，F 在 CD 上，AE 平分 ∠BAF。求证：AF = AB + FC。</p><p><strong>【解析】</strong></p><p>延长 CB 至 G，使 BG = FC，连 AG。</p><p>∵ ABCD 为正方形，∴ AB = AD，∠ABG = ∠ADF = 90°</p><p>又 BG = FC = DF（∵ BC = CD − FC − BF 关系中注意 CD = BC = 1）</p><p>在 ▵ABG 和 ▵ADF 中：</p><p>AB = AD，∠ABG = ∠ADF = 90°，BG = DF</p><p>∴ ▵ABG ≅ ▵ADF (SAS)</p><p>∴ ∠BAG = ∠DAF</p><p>又 ∠BAF = ∠BAE + ∠EAF，AE 平分 ∠BAF</p><p>∴ ∠BAE = ∠EAF</p><p>∠DAF = ∠BAF − 90° = 2∠BAE − 90°</p><p>∠BAG = ∠DAF</p><p>AG = AF（全等对应边）</p><p>AF = AG，而 AB + BG = AB + FC</p><p>∴ AF = AB + FC</p><p><strong>答：</strong> AF = AB + FC</p><p><strong>【方法提炼】</strong> 证明一条线段等于两段之和，常用&quot;截长补短法&quot;：延长（补短）或在长线段上截取（截长），构造全等三角形转化。</p><hr><h3 id="案例-9-正方形-旋转全等压轴-⭐⭐⭐⭐" tabindex="-1">案例 9：正方形 + 旋转全等压轴 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-9-正方形-旋转全等压轴-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 9：正方形 + 旋转全等压轴 ⭐⭐⭐⭐&quot;">​</a></h3><p><img src="'+e+'" alt="案例9示意图"></p><p><strong>【题目】</strong> 正方形 ABCD 的边长为 6，E 在 BC 上，F 在 CD 上，∠EAF = 45°，BE = 2。求 DF 的长。</p><p><strong>【解析】</strong></p><p>将 ▵ABE 绕 A 顺时针旋转 90° 到 ▵ADG 的位置。</p><p>则 G 在 CD 延长线上，DG = BE = 2，AG = AE</p><p>∠GAF = ∠GAD + ∠DAF = ∠BAE + ∠DAF</p><p>= ∠BAE + (∠BAD − ∠BAF) = ∠BAE + 90° − ∠BAF</p><p>又 ∠EAF = 45°，∴ ∠BAE + ∠FAD = 90° − 45° = 45°</p><p>∴ ∠GAF = ∠BAE + ∠FAD = 45°</p><p>在 ▵AEF 和 ▵AGF 中：</p><p>AE = AG，AF = AF，∠EAF = ∠GAF = 45°</p><p>∴ ▵AEF ≅ ▵AGF (SAS)</p><p>∴ EF = GF</p><p>EF = BE + CF（需证明 E、F 共线结论，本题中）</p><p>设 DF = x，则 CF = 6 − x</p><p>GF = DG + DF = 2 + x</p><p>EF = BE + CF → EF = 2 + 6 − x = 8 − x（需证明）</p><p>实际上由 ▵AEF ≅ ▵AGF：</p><p>EF = GF = 2 + x</p><p>又 EF² = BE² + (BC − BE)² ... 不直接</p><p>换方法：在 Rt▵ABE 中，AE² = 36 + 4 = 40</p><p>EF = GF = DG + DF = 2 + x</p><p>CF = 6 − x</p><p>在 Rt▵CEF 中：EF² = CE² + CF² = (6−2)² + (6−x)² = 16 + (6−x)²</p><p>又 EF = 2 + x</p><p>(2 + x)² = 16 + (6 − x)²</p><p>4 + 4x + x² = 16 + 36 − 12x + x²</p><p>4 + 4x = 52 − 12x</p><p>16x = 48</p><p>x = 3</p><p><strong>答：</strong> DF = 3</p><p><strong>【方法提炼】</strong> 正方形中 45° 角问题，旋转 90° 构造全等是经典方法。旋转后 ∠GAF = ∠EAF，证明 ▵AEF ≅ ▵AGF，从而 EF = GF，列方程求解。</p><hr><h3 id="案例-10-四边形-二次函数综合压轴-⭐⭐⭐⭐" tabindex="-1">案例 10：四边形 + 二次函数综合压轴 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-10-四边形-二次函数综合压轴-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 10：四边形 + 二次函数综合压轴 ⭐⭐⭐⭐&quot;">​</a></h3><p><img src="'+i+'" alt="案例10示意图"></p><p><strong>【题目】</strong> 抛物线 y = −x² + 2x + 3 与 x 轴交于 A、B（A 在 B 左侧），与 y 轴交于 C。在 ▵ABC 内作矩形 DEFG，其中 D、G 在 x 轴上，E 在 AC 上，F 在 BC 上。求矩形 DEFG 面积的最大值。</p><p><strong>【解析】</strong></p><p>A(−1, 0)，B(3, 0)，C(0, 3)</p><p>直线 AC：过 A(−1,0) 和 C(0,3)</p><p>斜率 k = (3−0)/(0−(−1)) = 3</p><p>y = 3x + 3</p><p>直线 BC：过 B(3,0) 和 C(0,3)</p><p>斜率 k = (3−0)/(0−3) = −1</p><p>y = −x + 3</p><p>设矩形 D(x&amp;sub1;, 0)，G(x&amp;sub2;, 0)，E(x&amp;sub1;, y&amp;sub1;)，F(x&amp;sub2;, y&amp;sub1;)</p><p>其中 E 在 AC 上：y&amp;sub1; = 3x&amp;sub1; + 3</p><p>F 在 BC 上：y&amp;sub1; = −x&amp;sub2; + 3</p><p>∴ 3x&amp;sub1; + 3 = −x&amp;sub2; + 3，x&amp;sub2; = −3x&amp;sub1;</p><p>矩形宽 = x&amp;sub2; − x&amp;sub1; = −3x&amp;sub1; − x&amp;sub1; = −4x&amp;sub1;</p><p>矩形高 = y&amp;sub1; = 3x&amp;sub1; + 3</p><p>需要 x&amp;sub1; ≤ 0（E 在 AC 上，x ∈ [−1, 0]），x&amp;sub2; ≥ 0</p><p>S = (−4x&amp;sub1;)(3x&amp;sub1; + 3) = −12x&amp;sub1;² − 12x&amp;sub1; = −12(x&amp;sub1;² + x&amp;sub1;)</p><p>= −12(x&amp;sub1; + ½)² + 3</p><p>当 x&amp;sub1; = −½ 时，S 取最大值 3</p><p>验证：x&amp;sub1; = −½ ∈ [−1, 0] ✓</p><p><strong>答：</strong> 矩形 DEFG 面积的最大值为 3</p><p><strong>【方法提炼】</strong> 四边形与二次函数综合题，关键是设变量表达矩形边长，建立面积的二次函数，配方求最值。注意变量的取值范围要满足几何约束。</p><hr><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题型</th><th>核心方法</th><th>易错点</th><th>难度</th></tr></thead><tbody><tr><td>矩形性质</td><td>对角线相等+勾股定理</td><td>混淆对角线与边的性质</td><td>⭐</td></tr><tr><td>菱形性质</td><td>对角线互相垂直+面积公式</td><td>面积公式记错为底×高</td><td>⭐</td></tr><tr><td>正方形性质</td><td>全等三角形转移角</td><td>忽略正方形的对称性</td><td>⭐⭐</td></tr><tr><td>折叠问题</td><td>折叠前后全等+勾股列方程</td><td>忘记折叠对应边相等</td><td>⭐⭐</td></tr><tr><td>动点问题</td><td>分类讨论+勾股定理</td><td>漏掉等腰三角形的情况</td><td>⭐⭐</td></tr><tr><td>菱形面积</td><td>面积等积法</td><td>不会用面积法转化</td><td>⭐⭐⭐</td></tr><tr><td>综合证明</td><td>平行且相等判定平行四边形</td><td>判定条件不充分</td><td>⭐⭐⭐</td></tr><tr><td>截长补短</td><td>构造全等三角形</td><td>不会作辅助线</td><td>⭐⭐⭐</td></tr><tr><td>旋转全等</td><td>旋转90°构造全等</td><td>旋转后角的关系算错</td><td>⭐⭐⭐⭐</td></tr><tr><td>二次函数综合</td><td>设变量建函数+配方求最值</td><td>几何约束转化为变量范围出错</td><td>⭐⭐⭐⭐</td></tr></tbody></table><p><strong>解题通法：</strong></p><ol><li><strong>判定问题</strong>：记住五种判定方法（定义 + 两组对边平行 + 一组对边平行且相等 + 对角线互相平分 + 两组对边分别相等）</li><li><strong>性质问题</strong>：矩形（直角 + 等对角线）、菱形（等边 + 垂直对角线）、正方形（全部性质）</li><li><strong>综合证明</strong>：先判定特殊四边形，再利用性质推导</li><li><strong>动点折叠</strong>：设变量 → 表达几何量 → 列方程 → 求解验证</li><li><strong>压轴综合</strong>：几何性质 + 代数运算结合，注意变量范围</li></ol>',200)])])}const G=p(C,[["render",D]]);export{c as __pageData,G as default};
